    /// THE crypto demo: full SHA-256 of "abc" in Verbose. Aggregates all
    /// the building blocks (bitwise primitives → rotr32 → ch/maj/sigmas →
    /// 64-round compression loop → K[i]/W[i] lookups) into a single
    /// recursive callable that produces the first 32-bit word of the hash.
    /// Compares against `echo -n abc | sha256sum` → ba7816bf... → first
    /// word = 0xba7816bf = 3128432319.
    ///
    /// Runs on a dedicated thread with a 16 MiB stack — the 64-deep
    /// nested if/else for K[i]/W[i] lookups recurses through the
    /// compiler's tree walkers and overflows the 2 MiB default test stack.
    #[test]
    fn sha256_abc_matches_sha256sum() {
        let handle = std::thread::Builder::new()
            .stack_size(64 * 1024 * 1024)
            .spawn(sha256_abc_test_body)
            .expect("spawn test thread");
        handle.join().expect("test thread panicked");
    }

    fn sha256_abc_test_body() {
        let src = std::fs::read_to_string("examples/sha256_abc.verbose")
            .expect("examples/sha256_abc.verbose must exist");
        let tokens = crate::lexer::Lexer::new(&src).tokenize().expect("tokenize");
        let program = crate::parser::Parser::new(tokens).parse_program().expect("parse");
        let out = std::env::temp_dir().join("verbosec_test_sha256_abc");
        compile_native(&program, "sha256_abc", out.to_str().unwrap(), false, false)
            .expect("sha256_abc must compile");
        #[cfg(unix)]
        {
            use std::os::unix::fs::PermissionsExt;
            let _ = std::fs::set_permissions(&out, std::fs::Permissions::from_mode(0o755));
        }
        let output = std::process::Command::new(&out)
            .arg("0")
            .output()
            .expect("native binary must run");
        let stdout = String::from_utf8_lossy(&output.stdout);
        // First 32-bit word of SHA-256("abc") = 0xba7816bf = 3128432319.
        // Matches `echo -n abc | sha256sum` which starts with ba7816bf.
        assert_eq!(
            stdout.as_ref(), "3128432319\n",
            "SHA-256('abc') first word mismatch with sha256sum (expected 0xba7816bf)"
        );
        let _ = std::fs::remove_file(&out);
    }

    /// Full 256-bit SHA-256 hash of "abc" — runs the parameterized binary
    /// 8 times (argv = 0..7), concatenates the words as hex, compares
    /// against `echo -n abc | sha256sum`. Byte-for-byte match.
    #[test]
    fn sha256_full_256bit_matches_sha256sum() {
        let handle = std::thread::Builder::new()
            .stack_size(64 * 1024 * 1024)
            .spawn(sha256_full_test_body)
            .expect("spawn test thread");
        handle.join().expect("test thread panicked");
    }

    fn sha256_full_test_body() {
        let src = std::fs::read_to_string("examples/sha256_full.verbose")
            .expect("examples/sha256_full.verbose must exist");
        let tokens = crate::lexer::Lexer::new(&src).tokenize().expect("tokenize");
        let program = crate::parser::Parser::new(tokens).parse_program().expect("parse");
        let out = std::env::temp_dir().join("verbosec_test_sha256_full");
        compile_native(&program, "sha256_word", out.to_str().unwrap(), false, false)
            .expect("sha256_word must compile");
        #[cfg(unix)]
        {
            use std::os::unix::fs::PermissionsExt;
            let _ = std::fs::set_permissions(&out, std::fs::Permissions::from_mode(0o755));
        }
        // SHA-256("abc") = ba7816bf 8f01cfea 414140de 5dae2223
        //                  b00361a3 96177a9c b410ff61 f20015ad
        let expected = [
            (0, "3128432319"), // 0xba7816bf
            (1, "2399260650"), // 0x8f01cfea
            (2, "1094795486"), // 0x414140de
            (3, "1571693091"), // 0x5dae2223
            (4, "2953011619"), // 0xb00361a3
            (5, "2518121116"), // 0x96177a9c
            (6, "3021012833"), // 0xb410ff61
            (7, "4060091821"), // 0xf20015ad
        ];
        let mut hex_acc = String::new();
        for (i, expected_val) in &expected {
            let output = std::process::Command::new(&out)
                .arg(i.to_string())
                .output()
                .expect("native binary must run");
            let stdout = String::from_utf8_lossy(&output.stdout);
            let stdout = stdout.trim();
            assert_eq!(
                stdout, *expected_val,
                "SHA-256('abc') word {} mismatch: got {}, expected {}",
                i, stdout, expected_val
            );
            let val: u64 = stdout.parse().expect("parse word");
            hex_acc.push_str(&format!("{:08x}", val));
        }
        // Full hash must equal `echo -n abc | sha256sum` output.
        assert_eq!(
            hex_acc,
            "ba7816bf8f01cfea414140de5dae2223b00361a396177a9cb410ff61f20015ad",
            "Concatenated SHA-256('abc') hex mismatch with sha256sum"
        );
        let _ = std::fs::remove_file(&out);
    }

    /// Generic SHA-256: hash any text input (up to 55 bytes, single block).
    /// The same compiled binary processes different argv inputs; each output
    /// matches `echo -n <input> | sha256sum` byte-for-byte for "abc",
    /// "hello", and empty string. Validates runtime W[0..15] packing from
    /// padded bytes + W[16..63] extension via sliding window.
    #[test]
    fn sha256_text_matches_sha256sum_for_multiple_inputs() {
        let handle = std::thread::Builder::new()
            .stack_size(64 * 1024 * 1024)
            .spawn(sha256_text_test_body)
            .expect("spawn test thread");
        handle.join().expect("test thread panicked");
    }

    fn sha256_text_test_body() {
        let src = std::fs::read_to_string("examples/sha256_text.verbose")
            .expect("examples/sha256_text.verbose must exist");
        let tokens = crate::lexer::Lexer::new(&src).tokenize().expect("tokenize");
        let program = crate::parser::Parser::new(tokens).parse_program().expect("parse");
        let out = std::env::temp_dir().join("verbosec_test_sha256_text");
        compile_native(&program, "sha256_word", out.to_str().unwrap(), false, false)
            .expect("sha256_word (generic) must compile");
        #[cfg(unix)]
        {
            use std::os::unix::fs::PermissionsExt;
            let _ = std::fs::set_permissions(&out, std::fs::Permissions::from_mode(0o755));
        }
        let inputs = [
            ("abc",   "ba7816bf8f01cfea414140de5dae2223b00361a396177a9cb410ff61f20015ad"),
            ("hello", "2cf24dba5fb0a30e26e83b2ac5b9e29e1b161e5c1fa7425e73043362938b9824"),
            ("",      "e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855"),
        ];
        for (input, expected_hex) in &inputs {
            let mut hex_acc = String::new();
            for i in 0..8 {
                let i_str = i.to_string();
                let output = std::process::Command::new(&out)
                    .args(&[*input, i_str.as_str()])
                    .output()
                    .expect("native binary must run");
                let stdout = String::from_utf8_lossy(&output.stdout);
                let val: u64 = stdout.trim().parse().expect("parse word");
                hex_acc.push_str(&format!("{:08x}", val));
            }
            assert_eq!(
                hex_acc, *expected_hex,
                "SHA-256({:?}) mismatch with sha256sum", input
            );
        }
        let _ = std::fs::remove_file(&out);
    }

    /// Multi-block SHA-256: input up to 119 bytes (1 or 2 blocks).
    /// Validates that padding spilling into a second block, plus the
    /// running hash state carried across blocks, produces the same
    /// output as sha256sum for inputs that straddle block boundaries.
    #[test]
    fn sha256_multi_2blocks_matches_sha256sum() {
        let handle = std::thread::Builder::new()
            .stack_size(64 * 1024 * 1024)
            .spawn(sha256_multi_test_body)
            .expect("spawn test thread");
        handle.join().expect("test thread panicked");
    }

    fn sha256_multi_test_body() {
        let src = std::fs::read_to_string("examples/sha256_multi.verbose")
            .expect("examples/sha256_multi.verbose must exist");
        let tokens = crate::lexer::Lexer::new(&src).tokenize().expect("tokenize");
        let program = crate::parser::Parser::new(tokens).parse_program().expect("parse");
        let out = std::env::temp_dir().join("verbosec_test_sha256_multi");
        compile_native(&program, "sha256_word", out.to_str().unwrap(), false, false)
            .expect("sha256_multi must compile");
        #[cfg(unix)]
        {
            use std::os::unix::fs::PermissionsExt;
            let _ = std::fs::set_permissions(&out, std::fs::Permissions::from_mode(0o755));
        }
        // Mix of 1-block and 2-block inputs.
        let inputs: &[(&str, &str)] = &[
            // 1-block
            ("",
             "e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7852b855"),
            ("abc",
             "ba7816bf8f01cfea414140de5dae2223b00361a396177a9cb410ff61f20015ad"),
            ("hello",
             "2cf24dba5fb0a30e26e83b2ac5b9e29e1b161e5c1fa7425e73043362938b9824"),
            ("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa",  // 55 'a's
             "9f4390f8d30c2dd92ec9f095b65e2b9ae9b0a925a5258e241c9f1e910f734318"),
            // 2-block: padding spills into block 1
            ("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa",  // 56 'a's
             "b35439a4ac6f0948b6d6f9e3c6af0f5f590ce20f1bde7090ef7970686ec6738a"),
            // 2-block: longer
            ("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa",  // 100 'a's
             "2816597888e4a0d3a36b82b83316ab32680eb8f00f8cd3b904d681246d285a0e"),
        ];
        for (input, expected_hex) in inputs {
            let mut hex_acc = String::new();
            for i in 0..8 {
                let i_str = i.to_string();
                let output = std::process::Command::new(&out)
                    .args(&[*input, i_str.as_str()])
                    .output()
                    .expect("native binary must run");
                let stdout = String::from_utf8_lossy(&output.stdout);
                let val: u64 = stdout.trim().parse().expect("parse word");
                hex_acc.push_str(&format!("{:08x}", val));
            }
            assert_eq!(
                hex_acc, *expected_hex,
                "SHA-256(len={}) mismatch with sha256sum", input.len()
            );
        }
        let _ = std::fs::remove_file(&out);
    }

    /// N-block SHA-256: text input up to 503 bytes (8 blocks max).
    /// Hits every block boundary (1, 2, 3, ..., 8 blocks) to validate
    /// the iterate_blocks recursion at scale. Each input is compared
    /// against sha256sum's first 32-bit word.
    #[test]
    fn sha256_nblocks_8block_boundaries() {
        let handle = std::thread::Builder::new()
            .stack_size(64 * 1024 * 1024)
            .spawn(sha256_nblocks_test_body)
            .expect("spawn test thread");
        handle.join().expect("test thread panicked");
    }

    // python3 is an oracle of convenience; some CI images (rust:alpine/musl)
    // don't ship it. Skip the python-oracle tests there instead of failing —
    // their job is cross-checking against hashlib, not gating the build on the
    // image having python.
    fn python3_available() -> bool {
        std::process::Command::new("python3")
            .arg("--version")
            .output()
            .map(|o| o.status.success())
            .unwrap_or(false)
    }

    fn sha256_nblocks_test_body() {
        use std::process::Command;
        if !python3_available() {
            eprintln!("skipping sha256_nblocks: python3 not available");
            return;
        }
        let src = std::fs::read_to_string("examples/sha256_nblocks.verbose")
            .expect("examples/sha256_nblocks.verbose must exist");
        let tokens = crate::lexer::Lexer::new(&src).tokenize().expect("tokenize");
        let program = crate::parser::Parser::new(tokens).parse_program().expect("parse");
        let out = std::env::temp_dir().join("verbosec_test_sha256_nblocks");
        compile_native(&program, "sha256_word", out.to_str().unwrap(), false, false)
            .expect("sha256_nblocks must compile");
        #[cfg(unix)]
        {
            use std::os::unix::fs::PermissionsExt;
            let _ = std::fs::set_permissions(&out, std::fs::Permissions::from_mode(0o755));
        }
        // Boundary-crossing inputs: just below and just at each new block.
        let lengths = [0usize, 55, 56, 119, 120, 183, 184, 247, 248, 311, 312, 375, 376, 439, 440, 503];
        for &len in &lengths {
            let input = "a".repeat(len);
            // Compute reference: sha256sum of `a` * len, first 32-bit word.
            // Use Python to avoid depending on sha256sum binary in the test env.
            let py = format!(
                "import hashlib;print(int(hashlib.sha256(b'a'*{}).hexdigest()[:8],16))",
                len
            );
            let reference = Command::new("python3")
                .arg("-c").arg(&py)
                .output()
                .expect("python3 must be available");
            let expected = String::from_utf8_lossy(&reference.stdout).trim().to_string();
            let output = Command::new(&out)
                .args(&[input.as_str(), "0"])
                .output()
                .expect("native binary must run");
            let got = String::from_utf8_lossy(&output.stdout).trim().to_string();
            assert_eq!(
                got, expected,
                "SHA-256(len={}) word 0 mismatch with Python", len
            );
        }
        let _ = std::fs::remove_file(&out);
    }

